import React, { useMemo, useState } from 'react';
import { useParams } from 'react-router-dom';
import CatalogGrid from '../components/Content/CatalogGrid';
import UsersCatalog from '../components/Content/UsersCatalog';
import MangaCatalog from '../components/Content/MangaCatalog';
import VideoCatalog from '../components/Content/VideoCatalog';
import CharactersCatalog from '../components/Content/CharactersCatalog';
import './CatalogPage.css';

const defaultFilters = {
  type: 'all',
  sortBy: 'popular',
  genres: []
};

const genres = [
  'Action', 'Romance', 'Drama', 'Comedy', 'Fantasy',
  'Sci-Fi', 'Horror', 'Mystery', 'Adventure', 'Slice of Life'
];

const getCategoryTitle = (cat) => {
  const titles = {
    users: 'Users',
    characters: 'Characters',
    titles: 'Titles',
    'reading-now': 'Reading Now',
    collections: 'Collections',
    reviews: 'Reviews',
    manga: 'Manga',
    'oel-manga': 'OEL Manga',
    manhwa: 'Manhwa',
    manhua: 'Manhua',
    'ru-manga': 'RuManga',
    comics: 'Comics',
    video: 'Video'
  };
  return titles[cat] || 'Catalog';
};

const getCategoryDescription = (cat) => {
  const descriptions = {
    users: 'Browse active users and their profiles.',
    characters: 'Popular characters from manga and anime.',
    titles: 'All titles in one place.',
    'reading-now': 'What users are reading now.',
    collections: 'Curated reading collections.',
    reviews: 'User reviews and ratings.',
    manga: 'Top manga selection.',
    manhwa: 'Popular webtoons and manhwa.',
    manhua: 'Chinese comics and stories.',
    video: 'Anime and related video content.'
  };
  return descriptions[cat] || 'Find your next favorite manga, manhwa or video.';
};

const getTypeForCategory = (category) => {
  const map = {
    manga: 'manga',
    manhwa: 'manhwa',
    manhua: 'manhua',
    video: 'video'
  };
  return map[category] || 'all';
};

const CatalogPage = () => {
  const { category } = useParams();
  const [filters, setFilters] = useState(defaultFilters);

  const activeFilters = useMemo(() => {
    const categoryType = getTypeForCategory(category);
    if (categoryType === 'all') {
      return filters;
    }
    return { ...filters, type: categoryType };
  }, [filters, category]);

  const handleFilterChange = (filterName, value) => {
    setFilters((prev) => ({
      ...prev,
      [filterName]: value
    }));
  };

  const handleGenreToggle = (genre) => {
    setFilters((prev) => ({
      ...prev,
      genres: prev.genres.includes(genre)
        ? prev.genres.filter((g) => g !== genre)
        : [...prev.genres, genre]
    }));
  };

  const handleResetFilters = () => {
    setFilters(defaultFilters);
  };

  const renderContent = () => {
    switch (category) {
      case 'users':
        return <UsersCatalog />;
      case 'characters':
        return <CharactersCatalog />;
      case 'video':
        return <VideoCatalog />;
      case 'manga':
      case 'manhwa':
      case 'manhua':
        return <MangaCatalog category={category} />;
      case 'titles':
      case 'reading-now':
      case 'collections':
      case 'reviews':
        return (
          <div className="catalog-main">
            <CatalogGrid
              filters={activeFilters}
              mode={category}
              heading={getCategoryTitle(category)}
              onResetFilters={handleResetFilters}
            />
          </div>
        );
      default:
        return (
          <>
            <div className="filters-sidebar">
              <div className="filter-section">
                <div className="filter-header">
                  <h3><i className="fas fa-filter"></i> Filters</h3>
                  <button className="reset-filters-btn" onClick={handleResetFilters}>
                    <i className="fas fa-redo"></i> Reset
                  </button>
                </div>

                <div className="filter-group">
                  <label><i className="fas fa-book"></i> Type</label>
                  <select
                    value={activeFilters.type}
                    onChange={(e) => handleFilterChange('type', e.target.value)}
                    className="filter-select"
                  >
                    <option value="all">All types</option>
                    <option value="manga">Manga</option>
                    <option value="manhwa">Manhwa</option>
                    <option value="manhua">Manhua</option>
                    <option value="video">Video</option>
                  </select>
                </div>

                <div className="filter-group">
                  <label><i className="fas fa-sort"></i> Sort by</label>
                  <select
                    value={activeFilters.sortBy}
                    onChange={(e) => handleFilterChange('sortBy', e.target.value)}
                    className="filter-select"
                  >
                    <option value="popular">Popularity</option>
                    <option value="newest">Newest</option>
                    <option value="rating">Rating</option>
                    <option value="views">Views</option>
                    <option value="chapters">Chapters</option>
                  </select>
                </div>

                <div className="filter-group">
                  <label><i className="fas fa-tags"></i> Genres</label>
                  <div className="genres-grid">
                    {genres.map((genre) => (
                      <button
                        key={genre}
                        className={`genre-tag ${activeFilters.genres.includes(genre) ? 'active' : ''}`}
                        onClick={() => handleGenreToggle(genre)}
                      >
                        {genre}
                        {activeFilters.genres.includes(genre) && <i className="fas fa-check"></i>}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            </div>

            <div className="catalog-main">
              <CatalogGrid filters={activeFilters} onResetFilters={handleResetFilters} />
            </div>
          </>
        );
    }
  };

  return (
    <div className="catalog-page">
      <div className="page-header">
        <div className="header-content">
          <h1>{getCategoryTitle(category)}</h1>
          <p>{getCategoryDescription(category)}</p>
          {category && category !== 'all' && (
            <div className="category-badge">
              <i className="fas fa-folder"></i>
              {getCategoryTitle(category)}
            </div>
          )}
        </div>
      </div>

      <div className="catalog-layout">{renderContent()}</div>
    </div>
  );
};

export default CatalogPage;
